const pct = v => `${Math.round((v||0)*100)}%`;

function MiniBar({ value, color, height=4 }) {
  // Removed visual bar per feedback - just shows nothing (callers show numbers directly)
  return null;
}

function SevPill({ severity, small }) {
  const s = SEV[severity];
  return (
    <span style={{display:"inline-flex",alignItems:"center",gap:5,background:s.bg,color:s.color,
      fontSize:small?10:12,fontWeight:600,padding:small?"2px 8px":"3px 10px",borderRadius:20,
      border:`1px solid ${s.color}28`,letterSpacing:0.2,whiteSpace:"nowrap"}}>
      <span style={{width:6,height:6,borderRadius:"50%",background:s.dot,flexShrink:0}}/>
      {s.label}
    </span>
  );
}

function ModelTag({ tag }) {
  const m = MODEL_TAG_LABELS[tag];
  if (!m) return null;
  return (
    <span style={{display:"inline-flex",alignItems:"center",gap:4,background:m.bg,color:m.color,
      fontSize:10,fontWeight:600,padding:"2px 8px",borderRadius:20,border:`1px solid ${m.color}28`,
      whiteSpace:"nowrap",letterSpacing:0.2}}>
      {m.label}
    </span>
  );
}

