// ── Model Detail ──────────────────────────────────────────────────
function ModelDetailPage({ model, onBack, onSelectObj }) {
  const [search, setSearch] = useState("");
  const [sevFilter, setSevFilter] = useState("all");

  const objects = useMemo(()=>{
    return MODEL_DATA.map(obj => {
      const t = obj.tests.find(x=>x.model===model.tag);
      return {...obj, modelF1: t?t.f1:null, modelRecall: t?t.recall:null, modelPrecision: t?t.precision:null,
        modelTP: t?t.tp:0, modelFP: t?t.fp:0, modelFN: t?t.fn:0};
    }).filter(o=>o.modelF1!==null);
  },[model]);

  const filtered = useMemo(()=>{
    let d = objects;
    if (sevFilter!=="all") d = d.filter(x=>x.severity===sevFilter);
    if (search) d = d.filter(x=>x.name.toLowerCase().includes(search.toLowerCase()));
    return [...d].sort((a,b)=>{const o={critical:0,warning:1,caution:2,good:3};return o[a.severity]-o[b.severity];});
  },[objects,sevFilter,search]);

  const counts = useMemo(()=>({
    critical:objects.filter(x=>x.severity==="critical").length,
    warning:objects.filter(x=>x.severity==="warning").length,
    caution:objects.filter(x=>x.severity==="caution").length,
    good:objects.filter(x=>x.severity==="good").length,
  }),[objects]);

  // Group by category
  const grouped = useMemo(()=>{
    const g={};
    filtered.forEach(o=>{if(!g[o.category])g[o.category]=[];g[o.category].push(o);});
    return g;
  },[filtered]);

  return (
    <div style={{flex:1,overflowY:"auto",background:C.pageBg}}>
      <PageHeader
        breadcrumb="AI Models"
        title={`${model.name} — ${model.day}`}
        subtitle={`${model.date} · ${model.objects} objects · ${model.tag==="day2_87"?"Coffee excluded from model":""}`}
        action={
          <div style={{display:"flex",gap:8,alignItems:"center"}}>
            <ModelTag tag={model.tag}/>
            <button onClick={onBack} style={{background:"none",border:`1px solid ${C.borderMid}`,color:C.textMid,borderRadius:8,padding:"7px 14px",fontSize:12,cursor:"pointer",fontWeight:600}}>
              ← All Models
            </button>
          </div>
        }
      />
      <div style={{padding:"24px 34px"}}>
        {/* Status summary */}
        <div style={{display:"grid",gridTemplateColumns:"repeat(4,1fr)",gap:12,marginBottom:24}}>
          {[["critical","Critical"],["warning","Needs Work"],["caution","Monitor"],["good","Passing"]].map(([key,label])=>{
            const s = SEV[key];
            const isActive = sevFilter===key;
            return (
              <button key={key} onClick={()=>setSevFilter(sevFilter===key?"all":key)} style={{
                background:isActive?s.bg:C.cardBg,border:`1px solid ${isActive?s.color+"50":C.border}`,
                borderRadius:10,padding:"16px 18px",cursor:"pointer",textAlign:"left",transition:"all 0.15s",
              }}>
                <div style={{display:"flex",justifyContent:"space-between",alignItems:"flex-start",marginBottom:8}}>
                  <span style={{width:8,height:8,borderRadius:"50%",background:s.dot,marginTop:4}}/>
                  <span style={{fontSize:28,fontWeight:800,color:isActive?s.color:C.text,fontVariantNumeric:"tabular-nums"}}>{counts[key]}</span>
                </div>
                <div style={{fontSize:12,fontWeight:700,color:isActive?s.color:C.text}}>{label}</div>
              </button>
            );
          })}
        </div>

        {/* Object table */}
        <div style={{background:C.cardBg,border:`1px solid ${C.border}`,borderRadius:12,overflow:"hidden"}}>
          <div style={{padding:"14px 22px",borderBottom:`1px solid ${C.border}`,display:"flex",gap:10,alignItems:"center",flexWrap:"wrap"}}>
            <h2 style={{fontSize:14,fontWeight:700,color:C.text,margin:0,marginRight:6}}>Objects in this Model</h2>
            <input value={search} onChange={e=>setSearch(e.target.value)} placeholder="Search..."
              style={{background:C.pageBg,border:`1px solid ${C.borderMid}`,borderRadius:8,color:C.text,
                padding:"6px 12px",fontSize:12,outline:"none",width:180}}/>
            <div style={{display:"flex",gap:4}}>
              {["all","critical","warning","caution","good"].map(s=>(
                <button key={s} onClick={()=>setSevFilter(sevFilter===s?"all":s)} style={{
                  background:sevFilter===s?(s==="all"?C.accBlue:SEV[s]?.dot||C.accBlue):C.pageBg,
                  color:sevFilter===s?"#fff":C.textMid,border:`1px solid ${C.borderMid}`,
                  borderRadius:6,padding:"5px 11px",fontSize:11,cursor:"pointer",fontWeight:600,textTransform:"capitalize",
                }}>{s}</button>
              ))}
            </div>
            <span style={{marginLeft:"auto",fontSize:12,color:C.textLight}}>{filtered.length} objects</span>
          </div>
          {/* Column headers */}
          <div style={{display:"grid",gridTemplateColumns:"1.8fr 80px 70px 80px 80px 80px 80px",
            padding:"8px 22px",background:C.pageBg,borderBottom:`1px solid ${C.border}`}}>
            {["Object","Units Sold","F1","Recall","Precision","FP / FN","Status"].map(h=>(
              <div key={h} style={{fontSize:10,color:C.textLight,fontWeight:600,textTransform:"uppercase",letterSpacing:0.6}}>{h}</div>
            ))}
          </div>
          <div>
            {Object.entries(grouped).map(([catKey,items])=>{
              const catCfg = CATEGORIES[catKey];
              return (
                <div key={catKey}>
                  <div style={{padding:"10px 22px 6px",display:"flex",alignItems:"center",gap:8}}>
                    <div style={{width:7,height:7,borderRadius:"50%",background:catCfg.color}}/>
                    <span style={{fontSize:11,fontWeight:700,color:catCfg.color,textTransform:"uppercase",letterSpacing:1}}>{catCfg.label}</span>
                    <span style={{fontSize:11,color:C.textLight}}>— {items.length}</span>
                    <div style={{flex:1,height:1,background:C.border,marginLeft:4}}/>
                  </div>
                  {items.map((obj,i)=>{
                    const s = SEV[obj.severity];
                    return (
                      <button key={obj.id} onClick={()=>onSelectObj(obj)} style={{
                        display:"grid",gridTemplateColumns:"1.8fr 80px 70px 80px 80px 80px 80px",
                        gap:0,alignItems:"center",width:"100%",padding:"11px 22px",
                        background:i%2===0?C.cardBg:"#FAFCFF",
                        borderLeft:"3px solid transparent",border:"none",cursor:"pointer",textAlign:"left",
                        borderBottom:`1px solid ${C.border}`,transition:"background 0.1s",
                      }}
                      onMouseEnter={e=>{e.currentTarget.style.background="#EEF4FF";e.currentTarget.style.borderLeft=`3px solid ${C.accBlue}`;}}
                      onMouseLeave={e=>{e.currentTarget.style.background=i%2===0?C.cardBg:"#FAFCFF";e.currentTarget.style.borderLeft="3px solid transparent";}}>
                        <div style={{display:"flex",alignItems:"center",gap:8}}>
                          <span style={{width:7,height:7,borderRadius:"50%",background:s.dot,flexShrink:0}}/>
                          <span style={{fontSize:13,color:C.text,fontWeight:500,overflow:"hidden",textOverflow:"ellipsis",whiteSpace:"nowrap"}}>{obj.name}</span>
                        </div>
                        <div style={{textAlign:"center"}}>
                          {SALES_DATA[obj.id] ? (
                            <div>
                              <div style={{fontSize:13,fontWeight:700,color:(obj.severity==="critical"||obj.severity==="warning")?C.critical:C.good}}>{SALES_DATA[obj.id].qty}</div>
                              <div style={{fontSize:9,color:C.textLight,marginTop:1}}>{SALES_DATA[obj.id].label}</div>
                            </div>
                          ) : <span style={{fontSize:12,color:C.textLight}}>—</span>}
                        </div>
                        <div>
                          <span style={{fontSize:13,fontWeight:700,color:obj.modelF1<0.5?C.critical:obj.modelF1<0.75?C.warning:obj.modelF1<0.9?C.caution:C.good}}>{pct(obj.modelF1)}</span>
                        </div>
                        <div style={{fontSize:12,color:C.textMid}}>{pct(obj.modelRecall)}</div>
                        <div style={{fontSize:12,color:C.textMid}}>{pct(obj.modelPrecision)}</div>
                        <div style={{fontSize:12,color:obj.modelFP>8?C.critical:C.textMid,fontWeight:obj.modelFP>8?600:400}}>{obj.modelFP} FP · {obj.modelFN} FN</div>
                        <div><SevPill severity={obj.severity} small/></div>
                      </button>
                    );
                  })}
                </div>
              );
            })}
          </div>
        </div>
      </div>
    </div>
  );
}

// ── Object Detail Page ────────────────────────────────────────────
function ObjectDetailPage({ obj, sourceModel, onBack }) {
  const [activeImg, setActiveImg] = useState(null);
  const imgIds = OBJ_TO_IMAGES[obj.id] || [];

  const modelTest = sourceModel ? obj.tests.find(t=>t.model===sourceModel.tag) : null;

  return (
    <div style={{flex:1,overflowY:"auto",background:C.pageBg}}>
      <PageHeader
        breadcrumb={sourceModel ? `AI Models → ${sourceModel.name}` : "Analysis"}
        title={obj.name}
        subtitle={`Object ID: ${obj.id} · ${CATEGORIES[obj.category]?.label}`}
        action={
          <button onClick={onBack} style={{background:"none",border:`1px solid ${C.borderMid}`,
            color:C.textMid,borderRadius:8,padding:"7px 14px",fontSize:12,cursor:"pointer",fontWeight:600}}>
            ← Back
          </button>
        }
      />
      <div style={{padding:"24px 34px"}}>
        <div style={{display:"grid",gridTemplateColumns:"1fr 340px",gap:16,marginBottom:20}}>

          {/* Left: Performance */}
          <div style={{display:"flex",flexDirection:"column",gap:14}}>
            {/* Overall status */}
            <div style={{background:C.cardBg,border:`1px solid ${C.border}`,borderRadius:12,padding:"20px 24px"}}>
              <div style={{display:"flex",justifyContent:"space-between",alignItems:"flex-start",marginBottom:16}}>
                <div>
                  <h2 style={{fontSize:14,fontWeight:700,color:C.text,margin:0}}>Performance Across All Tests</h2>
                  <p style={{fontSize:12,color:C.textMid,margin:"3px 0 0"}}>How this object scored in each model</p>
                </div>
                <SevPill severity={obj.severity}/>
              </div>
              <div style={{display:"flex",flexDirection:"column",gap:14}}>
                {obj.tests.map(t=>{
                  const ml = MODEL_TAG_LABELS[t.model];
                  return (
                    <div key={t.model} style={{background:C.pageBg,borderRadius:10,padding:"14px 16px"}}>
                      <div style={{display:"flex",justifyContent:"space-between",alignItems:"center",marginBottom:12}}>
                        <ModelTag tag={t.model}/>
                        <span style={{fontSize:18,fontWeight:800,fontVariantNumeric:"tabular-nums",
                          color:t.f1===0?C.critical:t.f1<0.5?C.critical:t.f1<0.75?C.warning:t.f1<0.9?C.caution:C.good}}>
                          F1 {pct(t.f1)}
                        </span>
                      </div>
                      <div style={{display:"grid",gridTemplateColumns:"repeat(3,1fr)",gap:8,marginBottom:10}}>
                        {[
                          {label:"Recall",val:t.recall,note:`${t.tp}/10 found`,warn:t.recall<0.4},
                          {label:"Precision",val:t.precision,note:`${t.fp} false alarms`,warn:t.precision<0.4},
                          {label:"Missed",val:t.fn/10,note:`${t.fn} items`,warn:t.fn>5},
                        ].map(({label,val,note,warn})=>(
                          <div key={label} style={{background:C.cardBg,borderRadius:8,padding:"10px 12px",textAlign:"center"}}>
                            <div style={{fontSize:17,fontWeight:800,color:warn?C.critical:C.accBlue,fontVariantNumeric:"tabular-nums"}}>{label==="Missed"?t.fn:pct(val)}</div>
                            <div style={{fontSize:10,color:C.textLight,marginTop:1}}>{label}</div>
                            <div style={{fontSize:10,color:C.textMid,marginTop:2}}>{note}</div>
                          </div>
                        ))}
                      </div>
                      {t.f1===0&&<div style={{background:"#FDF1F0",border:"1px solid #C9403028",borderRadius:6,padding:"7px 12px",fontSize:11,color:C.critical}}>Zero detections — object was completely invisible to this model</div>}
                    </div>
                  );
                })}
              </div>
            </div>

            {/* Recommendation */}
            <div style={{background:C.cardBg,border:`1px solid ${C.border}`,borderRadius:12,padding:"20px 24px"}}>
              <h2 style={{fontSize:14,fontWeight:700,color:C.text,margin:"0 0 12px"}}>Recommended Action</h2>
              <div style={{borderLeft:`3px solid ${SEV[obj.severity].dot}`,paddingLeft:14}}>
                <div style={{fontSize:12,fontWeight:700,color:SEV[obj.severity].color,marginBottom:6}}>{SEV[obj.severity].label}</div>
                <div style={{fontSize:13,color:C.textMid,lineHeight:1.7}}>
                  {obj.severity==="critical" && obj.avgRecall<0.3 &&
                    "Recollect this object. The model rarely detects it across tests — likely needs new training images captured at varied angles and distances in the deployment environment."}
                  {obj.severity==="critical" && obj.avgRecall>=0.3 &&
                    "Review training images. High false positives suggest this object is being confused with a similar-looking product nearby. Try recollecting in a cleaner environment."}
                  {obj.severity==="warning" &&
                    "Performance is inconsistent across test days. Consider recollecting with more varied angles, distances, and lighting conditions to help the model generalize better."}
                  {obj.severity==="caution" &&
                    "Performance is acceptable but has room to improve. Monitor in future tests before taking action. No immediate recollection needed."}
                  {obj.severity==="good" &&
                    "This object is performing well. No action required. Continue monitoring in future inference runs."}
                </div>
              </div>
            </div>
          </div>

          {/* Right: Totals */}
          <div style={{display:"flex",flexDirection:"column",gap:14}}>
            <div style={{background:C.cardBg,border:`1px solid ${C.border}`,borderRadius:12,padding:"20px 22px"}}>
              <h2 style={{fontSize:14,fontWeight:700,color:C.text,margin:"0 0 14px"}}>Totals Across All Tests</h2>
              <div style={{display:"grid",gridTemplateColumns:"1fr 1fr",gap:10,marginBottom:14}}>
                <div style={{background:"#FDF1F0",border:"1px solid #C9403020",borderRadius:8,padding:"14px",textAlign:"center"}}>
                  <div style={{fontSize:28,fontWeight:800,color:C.critical}}>{obj.totalFP}</div>
                  <div style={{fontSize:11,color:C.textLight,marginTop:2}}>False Positives</div>
                  <div style={{fontSize:10,color:C.textMid,marginTop:4,lineHeight:1.4}}>Detected when not present</div>
                </div>
                <div style={{background:"#FEF6EC",border:"1px solid #D4820A20",borderRadius:8,padding:"14px",textAlign:"center"}}>
                  <div style={{fontSize:28,fontWeight:800,color:C.warning}}>{obj.totalFN}</div>
                  <div style={{fontSize:11,color:C.textLight,marginTop:2}}>False Negatives</div>
                  <div style={{fontSize:10,color:C.textMid,marginTop:4,lineHeight:1.4}}>Present but not found</div>
                </div>
              </div>
              <div style={{background:C.pageBg,borderRadius:8,padding:"12px 14px"}}>
                <div style={{fontSize:11,color:C.textLight,marginBottom:6,fontWeight:600,textTransform:"uppercase",letterSpacing:0.8}}>F1 Trend</div>
                <div style={{display:"flex",gap:4}}>
                  {obj.tests.map((t,i)=>(
                    <div key={i} style={{flex:1}}>
                      <div style={{height:32,background:C.offWhite,borderRadius:6,overflow:"hidden",display:"flex",alignItems:"flex-end"}}>
                        <div style={{width:"100%",height:`${(t.f1||0)*100}%`,background:t.f1===0?C.critical:t.f1<0.5?C.critical:t.f1<0.75?C.warning:t.f1<0.9?C.caution:C.good,transition:"height 0.5s ease"}}/>
                      </div>
                      <div style={{fontSize:9,color:C.textLight,marginTop:4,textAlign:"center",lineHeight:1.2}}>{MODEL_TAG_LABELS[t.model]?.label.split("·")[0].trim()}</div>
                    </div>
                  ))}
                </div>
              </div>
            </div>

            {/* Category + ID */}
            <div style={{background:C.cardBg,border:`1px solid ${C.border}`,borderRadius:12,padding:"18px 22px"}}>
              <h2 style={{fontSize:14,fontWeight:700,color:C.text,margin:"0 0 12px"}}>Object Details</h2>
              <div style={{display:"flex",flexDirection:"column",gap:8}}>
                {[
                  {label:"Category",value:CATEGORIES[obj.category]?.label},
                  {label:"Object ID",value:obj.id,mono:true},
                  {label:"Severity",value:<SevPill severity={obj.severity} small/>},
                ].map(({label,value,mono})=>(
                  <div key={label} style={{display:"flex",justifyContent:"space-between",alignItems:"center",
                    padding:"8px 0",borderBottom:`1px solid ${C.border}`}}>
                    <span style={{fontSize:12,color:C.textLight}}>{label}</span>
                    {typeof value==="string"?
                      <span style={{fontSize:12,fontWeight:600,color:C.text,fontFamily:mono?"monospace":"inherit"}}>{value}</span>
                      :value}
                  </div>
                ))}
              </div>
            </div>
          </div>
        </div>

        {/* Inference Images */}
        <div style={{background:C.cardBg,border:`1px solid ${C.border}`,borderRadius:12,overflow:"hidden"}}>
          <div style={{padding:"18px 24px",borderBottom:`1px solid ${C.border}`}}>
            <h2 style={{fontSize:14,fontWeight:700,color:C.text,margin:0}}>Inference Images</h2>
            <p style={{fontSize:12,color:C.textMid,margin:"3px 0 0"}}>
              {imgIds.length>0
                ? `${imgIds.length} image${imgIds.length>1?"s":""} where this object was detected — bounding boxes and confidence scores shown`
                : "No inference images available for this object in the current dataset"}
            </p>
          </div>
          <div style={{padding:"20px 24px"}}>
            {imgIds.length===0 ? (
              <div style={{textAlign:"center",padding:"32px",color:C.textLight,fontSize:13}}>
                No images to display for this object
              </div>
            ) : (
              <>
                <div style={{display:"grid",gridTemplateColumns:`repeat(${Math.min(imgIds.length,2)},1fr)`,gap:14,marginBottom: activeImg?16:0}}>
                  {imgIds.map(imgId=>{
                    const src = INFERENCE_IMAGES[imgId];
                    const isActive = activeImg===imgId;
                    return (
                      <div key={imgId} onClick={()=>setActiveImg(isActive?null:imgId)} style={{
                        borderRadius:10,overflow:"hidden",cursor:"pointer",
                        border:`2px solid ${isActive?C.accBlue:C.border}`,
                        transition:"border-color 0.15s",
                      }}>
                        <img src={src} alt={`Inference ${imgId.slice(0,8)}`}
                          style={{width:"100%",display:"block",aspectRatio:"16/9",objectFit:"cover"}}/>
                        <div style={{padding:"10px 14px",background:C.pageBg,display:"flex",justifyContent:"space-between",alignItems:"center"}}>
                          <span style={{fontSize:11,color:C.textLight,fontFamily:"monospace"}}>{imgId.slice(0,8)}…</span>
                          <span style={{fontSize:11,color:isActive?C.accBlue:C.textMid,fontWeight:600}}>{isActive?"Hide detail":"View larger"}</span>
                        </div>
                      </div>
                    );
                  })}
                </div>
                {activeImg && (
                  <div style={{borderRadius:12,overflow:"hidden",border:`1px solid ${C.border}`}}>
                    <img src={INFERENCE_IMAGES[activeImg]} alt="Full inference frame"
                      style={{width:"100%",display:"block"}}/>
                    <div style={{padding:"12px 18px",background:C.pageBg,display:"flex",justifyContent:"space-between",alignItems:"center"}}>
                      <div>
                        <div style={{fontSize:12,fontWeight:600,color:C.text}}>Full inference frame</div>
                        <div style={{fontSize:11,color:C.textMid,marginTop:2}}>Red bounding boxes show all detections in this frame. Object IDs and confidence scores are labeled on each detection.</div>
                      </div>
                      <button onClick={()=>setActiveImg(null)} style={{background:"none",border:`1px solid ${C.borderMid}`,
                        color:C.textMid,borderRadius:6,padding:"5px 12px",fontSize:11,cursor:"pointer"}}>Close</button>
                    </div>
                  </div>
                )}
              </>
            )}
          </div>
        </div>
      </div>
    </div>
  );
}

// ── Analysis Page ─────────────────────────────────────────────────
function AnalysisPage({ onSelectObj }) {
  const [sevFilter, setSevFilter] = useState("all");
  const [catFilter, setCatFilter] = useState("all");
  const [search, setSearch] = useState("");

  const counts = useMemo(()=>({
    total:MODEL_DATA.length,
    critical:MODEL_DATA.filter(d=>d.severity==="critical").length,
    warning:MODEL_DATA.filter(d=>d.severity==="warning").length,
    caution:MODEL_DATA.filter(d=>d.severity==="caution").length,
    good:MODEL_DATA.filter(d=>d.severity==="good").length,
  }),[]);

  const filtered = useMemo(()=>{
    let d = MODEL_DATA;
    if (sevFilter!=="all") d=d.filter(x=>x.severity===sevFilter);
    if (catFilter!=="all") d=d.filter(x=>x.category===catFilter);
    if (search) d=d.filter(x=>x.name.toLowerCase().includes(search.toLowerCase()));
    return [...d].sort((a,b)=>{const o={critical:0,warning:1,caution:2,good:3};return o[a.severity]-o[b.severity];});
  },[sevFilter,catFilter,search]);

  const grouped = useMemo(()=>{
    const g={};
    filtered.forEach(o=>{if(!g[o.category])g[o.category]=[];g[o.category].push(o);});
    return g;
  },[filtered]);

  const recollect = MODEL_DATA.filter(d=>d.severity==="critical");

  return (
    <div style={{flex:1,overflowY:"auto",background:C.pageBg}}>
      <PageHeader breadcrumb="Amine Sphere" title="Analysis" subtitle={`Volante Pilot · 3 models · ${counts.total} objects · March 2026`}/>
      <div style={{padding:"24px 34px"}}>

        {/* Status cards */}
        <div style={{display:"grid",gridTemplateColumns:"repeat(4,1fr)",gap:12,marginBottom:22}}>
          {[["critical","Critical","Immediate action"],["warning","Needs Work","Inconsistent"],["caution","Monitor","Room to improve"],["good","Passing","Reliable"]].map(([key,label,sub])=>{
            const s=SEV[key]; const isActive=sevFilter===key;
            return (
              <button key={key} onClick={()=>setSevFilter(sevFilter===key?"all":key)} style={{
                background:isActive?s.bg:C.cardBg,border:`1px solid ${isActive?s.color+"50":C.border}`,
                borderRadius:10,padding:"16px 18px",cursor:"pointer",textAlign:"left",transition:"all 0.15s",
              }}>
                <div style={{display:"flex",justifyContent:"space-between",alignItems:"flex-start",marginBottom:8}}>
                  <span style={{width:8,height:8,borderRadius:"50%",background:s.dot,marginTop:4}}/>
                  <span style={{fontSize:28,fontWeight:800,color:isActive?s.color:C.text}}>{counts[key]}</span>
                </div>
                <div style={{fontSize:12,fontWeight:700,color:isActive?s.color:C.text}}>{label}</div>
                <div style={{fontSize:11,color:C.textLight,marginTop:1}}>{sub}</div>
                <div style={{marginTop:10,background:C.offWhite,borderRadius:99,height:3,overflow:"hidden"}}>
                  <div style={{width:`${(counts[key]/counts.total)*100}%`,height:"100%",background:s.dot,borderRadius:99}}/>
                </div>
              </button>
            );
          })}
        </div>

        <div style={{display:"grid",gridTemplateColumns:"1fr 360px",gap:16,marginBottom:22}}>
          {/* Key Takeaways */}
          <div style={{background:C.cardBg,border:`1px solid ${C.border}`,borderRadius:12}}>
            <div style={{padding:"18px 22px",borderBottom:`1px solid ${C.border}`}}>
              <h2 style={{fontSize:14,fontWeight:700,color:C.text,margin:0}}>Key Takeaways</h2>
            </div>
            <div style={{padding:"18px 22px",display:"grid",gridTemplateColumns:"1fr 1fr",gap:12}}>
              {[
                {t:"53% of objects are performing well",b:"47 objects scored above 0.9 F1 across all tests. The pilot has a strong foundation.",a:C.good},
                {t:"Beverages account for most failures",b:"Drinks have 4 of 6 critical failures. Similar bottle shapes are likely causing look-alike confusion.",a:C.critical},
                {t:"F1 alone doesn't tell the full story",b:"Powerade ION Zero has perfect recall but 33 false positives. Always review Recall and Precision separately.",a:C.warning},
                {t:"Removing coffee didn't fix core issues",b:"The 87-object model showed marginal gains. The same 6 objects continued to fail.",a:C.caution},
                {t:"High precision can hide low recall",b:"Pringles Hot Ones has 100% precision but only 33% recall — it rarely guesses but misses most items.",a:C.accBlue},
                {t:"Coke family products confuse each other",b:"Classic, Cherry, and Dr. Pepper all show sharp drops from Day 1 to Day 2 — similar labels causing cross-detections.",a:"#7A6FAD"},
              ].map(({t,b,a})=>(
                <div key={t} style={{padding:"12px 14px",background:C.pageBg,borderRadius:8,borderLeft:`3px solid ${a}`}}>
                  <div style={{fontSize:12,fontWeight:700,color:C.text,marginBottom:4,lineHeight:1.4}}>{t}</div>
                  <div style={{fontSize:11,color:C.textMid,lineHeight:1.6}}>{b}</div>
                </div>
              ))}
            </div>
          </div>

          {/* Recollect queue */}
          <div style={{background:C.cardBg,border:`1px solid ${C.border}`,borderRadius:12}}>
            <div style={{padding:"18px 22px",borderBottom:`1px solid ${C.border}`}}>
              <h2 style={{fontSize:14,fontWeight:700,color:C.text,margin:0}}>Priority Recollection Queue</h2>
              <p style={{fontSize:12,color:C.textMid,margin:"3px 0 0"}}>{recollect.length} objects — immediate action required</p>
            </div>
            <div style={{padding:"14px 18px",display:"flex",flexDirection:"column",gap:10}}>
              {recollect.map(obj=>{
                const catCfg=CATEGORIES[obj.category];
                return (
                  <button key={obj.id} onClick={()=>onSelectObj(obj,null)} style={{
                    background:C.pageBg,border:`1px solid ${C.border}`,borderRadius:10,padding:"13px 15px",
                    cursor:"pointer",textAlign:"left",width:"100%",
                    transition:"border-color 0.15s",
                  }}
                  onMouseEnter={e=>e.currentTarget.style.borderColor=C.accBlue}
                  onMouseLeave={e=>e.currentTarget.style.borderColor=C.border}>
                    <div style={{display:"flex",justifyContent:"space-between",alignItems:"flex-start",marginBottom:10}}>
                      <div style={{flex:1,minWidth:0}}>
                        <div style={{fontSize:12,fontWeight:700,color:C.text,overflow:"hidden",textOverflow:"ellipsis",whiteSpace:"nowrap"}}>{obj.name}</div>
                        <div style={{fontSize:10,color:catCfg.color,marginTop:2,fontWeight:600}}>{catCfg.label}</div>
                      </div>
                      <div style={{fontSize:20,fontWeight:800,color:C.critical,marginLeft:8,flexShrink:0,fontVariantNumeric:"tabular-nums"}}>{pct(obj.avgF1)}</div>
                    </div>
                    <div style={{display:"grid",gridTemplateColumns:"repeat(3,1fr)",gap:6,marginBottom:8}}>
                      {[
                        {l:"Recall",v:pct(obj.avgRecall),w:obj.avgRecall<0.4},
                        {l:"Precision",v:pct(obj.avgPrecision),w:obj.avgPrecision<0.4},
                        {l:"False +",v:obj.totalFP,w:obj.totalFP>5},
                      ].map(({l,v,w})=>(
                        <div key={l} style={{background:C.cardBg,borderRadius:6,padding:"6px 8px",textAlign:"center"}}>
                          <div style={{fontSize:13,fontWeight:700,color:w?C.critical:C.textMid}}>{v}</div>
                          <div style={{fontSize:9,color:C.textLight,marginTop:1}}>{l}</div>
                        </div>
                      ))}
                    </div>
                    <div style={{display:"flex",gap:3}}>
                      {obj.tests.map((t,i)=>(
                        <div key={i} title={`${t.test}: ${pct(t.f1)}`} style={{flex:1,height:4,borderRadius:99,
                          background:t.f1===0?C.critical:t.f1<0.5?C.critical:t.f1<0.75?C.warning:C.caution}}/>
                      ))}
                    </div>
                    <div style={{fontSize:9,color:C.textLight,marginTop:4}}>F1 across 3 tests · click to investigate</div>
                  </button>
                );
              })}
            </div>
          </div>
        </div>

        {/* Revenue at Risk Banner */}
        {(()=>{
          const atRisk = MODEL_DATA
            .filter(o => SALES_DATA[o.id] && (o.severity==="critical" || o.severity==="warning"))
            .sort((a,b)=>(SALES_DATA[b.id]?.qty||0)-(SALES_DATA[a.id]?.qty||0));
          const totalAtRisk = atRisk.reduce((sum,o)=>sum+(SALES_DATA[o.id]?.qty||0),0);
          const topSellers = MODEL_DATA
            .filter(o => SALES_DATA[o.id])
            .sort((a,b)=>(SALES_DATA[b.id]?.qty||0)-(SALES_DATA[a.id]?.qty||0))
            .slice(0,5);
          if (atRisk.length === 0) return null;
          return (
            <div style={{background:C.cardBg,border:`1px solid ${C.border}`,borderRadius:12,overflow:"hidden",marginBottom:22}}>
              <div style={{padding:"18px 24px",borderBottom:`1px solid ${C.border}`,display:"flex",justifyContent:"space-between",alignItems:"center"}}>
                <div>
                  <h2 style={{fontSize:14,fontWeight:700,color:C.text,margin:0}}>Revenue at Risk</h2>
                  <p style={{fontSize:12,color:C.textMid,margin:"3px 0 0"}}>
                    Objects with real sales velocity that the model cannot reliably detect — sorted by units sold
                  </p>
                </div>
                <div style={{textAlign:"right"}}>
                  <div style={{fontSize:22,fontWeight:800,color:C.critical,fontVariantNumeric:"tabular-nums"}}>{totalAtRisk} units</div>
                  <div style={{fontSize:11,color:C.textLight,marginTop:1}}>combined sales · {atRisk.length} failing objects</div>
                </div>
              </div>
              <div style={{display:"grid",gridTemplateColumns:"repeat(3,1fr)",gap:0}}>
                {atRisk.slice(0,6).map((obj,i)=>{
                  const s = SEV[obj.severity];
                  const sd = SALES_DATA[obj.id];
                  const shareOfSales = ((sd.qty / TOTAL_UNITS)*100).toFixed(1);
                  return (
                    <button key={obj.id} onClick={()=>onSelectObj(obj,null)} style={{
                      padding:"18px 22px",
                      borderRight: i%3!==2 ? `1px solid ${C.border}` : "none",
                      borderBottom: i<3 && atRisk.slice(0,6).length>3 ? `1px solid ${C.border}` : "none",
                      background:"transparent",border:"none",
                      borderRight: i%3!==2?`1px solid ${C.border}`:"none",
                      borderBottom: i<3&&atRisk.length>3?`1px solid ${C.border}`:"none",
                      cursor:"pointer",textAlign:"left",transition:"background 0.12s",
                    }}
                    onMouseEnter={e=>e.currentTarget.style.background=C.pageBg}
                    onMouseLeave={e=>e.currentTarget.style.background="transparent"}>
                      <div style={{display:"flex",justifyContent:"space-between",alignItems:"flex-start",marginBottom:10}}>
                        <div style={{flex:1,minWidth:0,marginRight:8}}>
                          <div style={{fontSize:13,fontWeight:700,color:C.text,overflow:"hidden",textOverflow:"ellipsis",whiteSpace:"nowrap"}}>{obj.name.split("-")[0].trim()}</div>
                          <div style={{fontSize:10,color:CATEGORIES[obj.category]?.color,fontWeight:600,marginTop:2}}>{CATEGORIES[obj.category]?.label}</div>
                        </div>
                        <SevPill severity={obj.severity} small/>
                      </div>
                      <div style={{display:"grid",gridTemplateColumns:"1fr 1fr 1fr",gap:8}}>
                        <div style={{background:C.pageBg,borderRadius:7,padding:"8px 10px",textAlign:"center"}}>
                          <div style={{fontSize:18,fontWeight:800,color:C.critical,fontVariantNumeric:"tabular-nums"}}>{sd.qty}</div>
                          <div style={{fontSize:9,color:C.textLight,marginTop:1}}>Units Sold</div>
                          <div style={{fontSize:9,color:C.textMid,marginTop:1}}>{sd.label}</div>
                        </div>
                        <div style={{background:C.pageBg,borderRadius:7,padding:"8px 10px",textAlign:"center"}}>
                          <div style={{fontSize:18,fontWeight:800,color:obj.avgF1<0.5?C.critical:C.warning,fontVariantNumeric:"tabular-nums"}}>{pct(obj.avgF1)}</div>
                          <div style={{fontSize:9,color:C.textLight,marginTop:1}}>Avg F1</div>
                          <div style={{fontSize:9,color:C.textMid,marginTop:1}}>{obj.severity==="critical"?"Critical":"Needs Work"}</div>
                        </div>
                        <div style={{background:C.pageBg,borderRadius:7,padding:"8px 10px",textAlign:"center"}}>
                          <div style={{fontSize:18,fontWeight:800,color:C.textMid,fontVariantNumeric:"tabular-nums"}}>{shareOfSales}%</div>
                          <div style={{fontSize:9,color:C.textLight,marginTop:1}}>of Sales</div>
                          <div style={{fontSize:9,color:C.textMid,marginTop:1}}>this period</div>
                        </div>
                      </div>
                      <div style={{marginTop:10,background:C.offWhite,borderRadius:99,height:3,overflow:"hidden"}}>
                        <div style={{width:`${shareOfSales}%`,height:"100%",background:s.dot,borderRadius:99}}/>
                      </div>
                    </button>
                  );
                })}
              </div>
            </div>
          );
        })()}
        
                {/* Full object list with model column */}
        <div style={{background:C.cardBg,border:`1px solid ${C.border}`,borderRadius:12,overflow:"hidden"}}>
          <div style={{padding:"14px 22px",borderBottom:`1px solid ${C.border}`,display:"flex",gap:10,alignItems:"center",flexWrap:"wrap"}}>
            <h2 style={{fontSize:14,fontWeight:700,color:C.text,margin:0,marginRight:6}}>All Objects</h2>
            <input value={search} onChange={e=>setSearch(e.target.value)} placeholder="Search objects..."
              style={{background:C.pageBg,border:`1px solid ${C.borderMid}`,borderRadius:8,color:C.text,padding:"6px 12px",fontSize:12,outline:"none",width:190}}/>
            <div style={{display:"flex",gap:4}}>
              {Object.entries(CATEGORIES).map(([k,v])=>(
                <button key={k} onClick={()=>setCatFilter(catFilter===k?"all":k)} style={{
                  background:catFilter===k?v.color:C.pageBg,color:catFilter===k?"#fff":C.textMid,
                  border:`1px solid ${C.borderMid}`,borderRadius:6,padding:"4px 10px",fontSize:11,cursor:"pointer",fontWeight:600,
                }}>{v.label}</button>
              ))}
            </div>
            <div style={{display:"flex",gap:4}}>
              {["all","critical","warning","caution","good"].map(s=>(
                <button key={s} onClick={()=>setSevFilter(sevFilter===s?"all":s)} style={{
                  background:sevFilter===s?(s==="all"?C.accBlue:SEV[s]?.dot||C.accBlue):C.pageBg,
                  color:sevFilter===s?"#fff":C.textMid,border:`1px solid ${C.borderMid}`,
                  borderRadius:6,padding:"4px 10px",fontSize:11,cursor:"pointer",fontWeight:600,textTransform:"capitalize",
                }}>{s}</button>
              ))}
            </div>
            <span style={{marginLeft:"auto",fontSize:12,color:C.textLight}}>{filtered.length} objects</span>
          </div>
          {/* Column headers */}
          <div style={{display:"grid",gridTemplateColumns:"1.8fr 80px 70px 80px 80px 80px 110px 80px",
            padding:"8px 22px",background:C.pageBg,borderBottom:`1px solid ${C.border}`}}>
            {["Object","Units Sold","Avg F1","Recall","Precision","FP / FN","Models","Status"].map(h=>(
              <div key={h} style={{fontSize:10,color:C.textLight,fontWeight:600,textTransform:"uppercase",letterSpacing:0.6}}>{h}</div>
            ))}
          </div>
          <div>
            {Object.entries(grouped).map(([catKey,items])=>{
              const catCfg=CATEGORIES[catKey];
              return (
                <div key={catKey}>
                  <div style={{padding:"10px 22px 6px",display:"flex",alignItems:"center",gap:8}}>
                    <div style={{width:7,height:7,borderRadius:"50%",background:catCfg.color}}/>
                    <span style={{fontSize:11,fontWeight:700,color:catCfg.color,textTransform:"uppercase",letterSpacing:1}}>{catCfg.label}</span>
                    <span style={{fontSize:11,color:C.textLight}}>— {items.length}</span>
                    <div style={{flex:1,height:1,background:C.border,marginLeft:4}}/>
                  </div>
                  {items.map((obj,i)=>{
                    const s=SEV[obj.severity];
                    return (
                      <button key={obj.id} onClick={()=>onSelectObj(obj,null)} style={{
                        display:"grid",gridTemplateColumns:"1.8fr 80px 70px 80px 80px 80px 110px 80px",
                        gap:0,alignItems:"center",width:"100%",padding:"11px 22px",
                        background:i%2===0?C.cardBg:"#FAFCFF",border:"none",cursor:"pointer",textAlign:"left",
                        borderLeft:"3px solid transparent",borderBottom:`1px solid ${C.border}`,transition:"all 0.1s",
                      }}
                      onMouseEnter={e=>{e.currentTarget.style.background="#EEF4FF";e.currentTarget.style.borderLeft=`3px solid ${C.accBlue}`;}}
                      onMouseLeave={e=>{e.currentTarget.style.background=i%2===0?C.cardBg:"#FAFCFF";e.currentTarget.style.borderLeft="3px solid transparent";}}>
                        <div style={{display:"flex",alignItems:"center",gap:8}}>
                          <span style={{width:7,height:7,borderRadius:"50%",background:s.dot,flexShrink:0}}/>
                          <div style={{minWidth:0}}>
                            <span style={{fontSize:13,color:C.text,fontWeight:500,overflow:"hidden",textOverflow:"ellipsis",whiteSpace:"nowrap",display:"block"}}>{obj.name}</span>
                            {SALES_DATA[obj.id]&&(obj.severity==="critical"||obj.severity==="warning")&&(
                              <span style={{fontSize:10,color:C.critical,fontWeight:600}}>High-volume failure</span>
                            )}
                          </div>
                        </div>
                        <div style={{textAlign:"center"}}>
                          {SALES_DATA[obj.id] ? (
                            <div>
                              <div style={{fontSize:13,fontWeight:700,color:(obj.severity==="critical"||obj.severity==="warning")?C.critical:C.good}}>{SALES_DATA[obj.id].qty}</div>
                              <div style={{fontSize:9,color:C.textLight,marginTop:1}}>{SALES_DATA[obj.id].label}</div>
                            </div>
                          ) : <span style={{fontSize:12,color:C.textLight}}>—</span>}
                        </div>
                        <div>
                          <span style={{fontSize:13,fontWeight:700,color:obj.avgF1<0.5?C.critical:obj.avgF1<0.75?C.warning:obj.avgF1<0.9?C.caution:C.good}}>{pct(obj.avgF1)}</span>
                        </div>
                        <div style={{fontSize:12,color:C.textMid}}>{pct(obj.avgRecall)}</div>
                        <div style={{fontSize:12,color:C.textMid}}>{pct(obj.avgPrecision)}</div>
                        <div style={{fontSize:12,color:obj.totalFP>10?C.critical:C.textMid,fontWeight:obj.totalFP>10?600:400}}>{obj.totalFP} / {obj.totalFN}</div>
                        <div style={{display:"flex",flexDirection:"column",gap:2}}>
                          {obj.tests.map(t=>{
                            const ml=MODEL_TAG_LABELS[t.model];
                            return (
                              <div key={t.model} style={{display:"flex",alignItems:"center",gap:3}}>
                                <div style={{width:5,height:5,borderRadius:"50%",background:ml.color,flexShrink:0}}/>
                                <span style={{fontSize:9,color:C.textLight,whiteSpace:"nowrap",overflow:"hidden",textOverflow:"ellipsis"}}>{ml.label.split("·")[0].trim()}</span>
                                <span style={{fontSize:9,fontWeight:700,color:t.f1<0.5?C.critical:t.f1<0.8?C.warning:C.good,marginLeft:"auto"}}>{pct(t.f1)}</span>
                              </div>
                            );
                          })}
                        </div>
                        <div><SevPill severity={obj.severity} small/></div>
                      </button>
                    );
                  })}
                </div>
              );
            })}
          </div>
        </div>
      </div>
    </div>
  );
}

// ── App ───────────────────────────────────────────────────────────
export default function App() {
  const [page, setPage] = useState("ai_models");
  const [selectedModel, setSelectedModel] = useState(null);
  const [selectedObj, setSelectedObj] = useState(null);
  const [objSourceModel, setObjSourceModel] = useState(null);

  const handleNav = (id) => {
    setPage(id);
    if (id==="ai_models") { setSelectedModel(null); setSelectedObj(null); }
    if (id==="analysis") { setSelectedObj(null); }
  };

  const handleSelectModel = (model) => {
    setSelectedModel(model);
    setPage("model_detail");
  };

  const handleSelectObj = (obj, sourceModel) => {
    setSelectedObj(obj);
    setObjSourceModel(sourceModel);
    setPage("object_detail");
  };

  const handleBackFromObj = () => {
    if (objSourceModel) { setPage("model_detail"); }
    else { setPage("analysis"); }
    setSelectedObj(null);
  };

  const handleBackFromModel = () => {
    setPage("ai_models");
    setSelectedModel(null);
  };

  return (
    <div style={{display:"flex",height:"100vh",background:C.pageBg,fontFamily:"'Segoe UI','SF Pro Text',system-ui,sans-serif"}}>
      <style>{`
        *{box-sizing:border-box;margin:0;padding:0;}
        ::-webkit-scrollbar{width:5px;}
        ::-webkit-scrollbar-track{background:transparent;}
        ::-webkit-scrollbar-thumb{background:rgba(0,54,108,0.18);border-radius:99px;}
        input:focus{box-shadow:0 0 0 2px ${C.accBlue}30;border-color:${C.accBlue}!important;}
      `}</style>
      <Sidebar active={page} onNav={handleNav}/>
      {page==="ai_models"    && <AIModelsPage onNav={handleNav} onSelectModel={handleSelectModel}/>}
      {page==="model_detail" && selectedModel && <ModelDetailPage model={selectedModel} onBack={handleBackFromModel} onSelectObj={(obj)=>handleSelectObj(obj,selectedModel)}/>}
      {page==="analysis"     && <AnalysisPage onSelectObj={handleSelectObj}/>}
      {page==="object_detail"&& selectedObj   && <ObjectDetailPage obj={selectedObj} sourceModel={objSourceModel} onBack={handleBackFromObj}/>}
      {!["ai_models","model_detail","analysis","object_detail"].includes(page) && (
        <div style={{flex:1,display:"flex",alignItems:"center",justifyContent:"center",flexDirection:"column",gap:10}}>
          <div style={{fontSize:36,opacity:0.12,color:C.amnBlue}}>◎</div>
          <div style={{fontSize:13,color:C.textLight}}>Select a section from the navigation</div>
        </div>
      )}
    </div>
  );
}
